module top_module(DATAOUT, clock, reset, MODE, obf_DATAIN);output reg [3:0] DATAOUT;
  input clock, reset;
  input [1:0] MODE;
  input [3:0] obf_DATAIN;

  always @(posedge clock)
  begin
    if(reset)
      DATAOUT <= 0;
    else
      begin
        case(MODE)
          2'b00 : DATAOUT <= DATAOUT;      
          2'b01 : DATAOUT <= {obf_DATAIN[0], DATAOUT[3:1]};
          2'b10 : DATAOUT <= {DATAOUT[2:0], obf_DATAIN[0]};
          2'b11 : DATAOUT <= obf_DATAIN;       
        endcase
      end
  end

endmodule
